function calcCal(age, sex, hCm, wKg, act, preg) {
  const hM = hCm / 100;
  const bmi = wKg / (hM * hM);
  let c;

  if (age < 3) {
    c = sex === "male" ? 1000 + age * 50 : 950 + age * 50;
  } else if (age <= 18) {
    const p =
      sex === "male"
        ? act === "sedentary"
          ? 1.0
          : act === "moderate"
          ? 1.13
          : 1.26
        : act === "sedentary"
        ? 1.0
        : act === "moderate"
        ? 1.16
        : 1.31;
    c =
      sex === "male"
        ? 88.5 - 61.9 * age + p * (26.7 * wKg + 903 * hM) + 20
        : 135.3 - 30.8 * age + p * (10.0 * wKg + 934 * hM) + 25;
  } else {
    // Adults 19+
    if (bmi >= 25) {
      // Overweight/obese adult equations
      const p =
        sex === "male"
          ? act === "sedentary"
            ? 1.0
            : act === "moderate"
            ? 1.12
            : 1.29
          : act === "sedentary"
          ? 1.0
          : act === "moderate"
          ? 1.16
          : 1.27;
      c =
        sex === "male"
          ? 1086 - 10.1 * age + p * (13.7 * wKg + 416 * hM)
          : 448 - 7.95 * age + p * (11.4 * wKg + 619 * hM);
    } else {
      // Healthy weight adult equations
      const p =
        sex === "male"
          ? act === "sedentary"
            ? 1.0
            : act === "moderate"
            ? 1.11
            : 1.25
          : act === "sedentary"
          ? 1.0
          : act === "moderate"
          ? 1.12
          : 1.27;
      c =
        sex === "male"
          ? 662 - 9.53 * age + p * (15.91 * wKg + 539.6 * hM)
          : 354 - 6.91 * age + p * (9.36 * wKg + 726 * hM);
    }
  }

  if (preg === "pregnant") c += 340;
  if (preg === "lactating") c += 500;
  return Math.round(c / 200) * 200;
}
