function getTgt(cal) {
  const ls = Object.keys(TGT)
    .map(Number)
    .sort((a, b) => a - b);
  return TGT[
    ls.reduce((p, c) => (Math.abs(c - cal) < Math.abs(p - cal) ? c : p))
  ];
}

